const { S3Client, PutObjectCommand } = require("@aws-sdk/client-s3");
exports.handler = async (event) => {
    const s3 = new S3Client({ region: "REGION" });

    for(const record of event.Records) {
        const bucketName = record.s3.bucket.name;
        const originalKey = decodeURIComponent(record.s3.object.key.replace(/\+/g, ' '));
        const outputBucketName = "OUTPUT_BUCKET_NAME";
        const outputKey = originalKey.replace(/^(.*?)\./, ".processed."); // replace the extension and add '.processed.' prefix

        const fileParams = {
            Bucket: bucketName,
            Key: originalKey,
            Expires: 60,
            ResponseContentType: record.s3.object.contentType
        };
        const signedUrl = await s3Client.getSignedUrl('getObject', fileParams);

        // Process the file using the processFile function here
        const processedData = await processFile(signedUrl);

        const putParams = {
            Bucket: outputBucketName,
            Key: outputKey,
            Body: JSON.stringify(processedData),
            ContentType: 'application/json'
        };
        await s3Client.send(new PutObjectCommand(putParams));
    }
};